import{_ as s,o as a,c as e,ag as t}from"./chunks/framework.BLeoozAw.js";const l="/Awesome-SRC-experience/img/Screenshot-2023-06-15-at-10.46.03-AM-1536x816.webp",p="/Awesome-SRC-experience/img/Screenshot-2023-06-15-at-10.52.04-AM.webp",h="/Awesome-SRC-experience/img/Screenshot-2023-06-15-at-10.58.41-AM.webp",n="/Awesome-SRC-experience/img/Screenshot-2023-06-15-at-4.58.13-PM-1536x795.webp",c="/Awesome-SRC-experience/img/Screenshot-2023-06-15-at-5.02.37-PM-1536x781.webp",r="/Awesome-SRC-experience/img/Screenshot-2023-06-15-at-5.04.33-PM.webp",o="/Awesome-SRC-experience/img/Screenshot-2023-06-15-at-5.18.00-PM-1536x625.webp",k="/Awesome-SRC-experience/img/Screenshot-2023-06-15-at-5.28.34-PM-1536x838.webp",d="/Awesome-SRC-experience/img/Screenshot-2023-06-15-at-5.23.06-PM-1536x1097.webp",g="/Awesome-SRC-experience/img/Screenshot-2023-06-15-at-5.23.12-PM-1536x695.webp",u="/Awesome-SRC-experience/img/Screenshot-2023-06-15-at-5.47.33-PM.webp",F="/Awesome-SRC-experience/img/Screenshot-2023-06-15-at-5.54.08-PM.webp",S=JSON.parse('{"title":"Nuclei：最全教程","description":"","frontmatter":{},"headers":[],"relativePath":"tools/漏扫工具/nuclei-intro.md","filePath":"tools/漏扫工具/nuclei-intro.md"}'),m={name:"tools/漏扫工具/nuclei-intro.md"};function b(C,i,y,B,v,x){return a(),e("div",null,[...i[0]||(i[0]=[t(`<h1 id="nuclei-最全教程" tabindex="-1">Nuclei：最全教程 <a class="header-anchor" href="#nuclei-最全教程" aria-label="Permalink to &quot;Nuclei：最全教程&quot;">​</a></h1><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>在这篇文章中，你将学习Nuclei是什么，它是如何工作的以及所有与该工具相关的命令。</p><h2 id="什么是-nuclei" tabindex="-1">什么是 Nuclei <a class="header-anchor" href="#什么是-nuclei" aria-label="Permalink to &quot;什么是 Nuclei&quot;">​</a></h2><p>Nuclei是一款漏洞分析工具。Nuclei通过基于模板向目标发送请求，从而实现零误报，并能够快速扫描大量主机。</p><p>Nuclei支持多种协议进行扫描，包括TCP、DNS、HTTP、SSL、FILE、Whois、Websocket、Headless等等。</p><p>仅仅使用Nuclei，我们就可以进行大量的安全检查，其结果非常出色。</p><p>Nuclei的一些替代工具包括IpenVAS、Nessus、Nikto。我个人比较喜欢Nessus和OpenVAS。</p><p>简单来说，Nuclei是一款具有额外功能的漏洞分析工具。</p><h2 id="nuclei-的特性" tabindex="-1">Nuclei 的特性 <a class="header-anchor" href="#nuclei-的特性" aria-label="Permalink to &quot;Nuclei 的特性&quot;">​</a></h2><ul><li>基于YAML的模板</li><li>可扩展的模板库</li><li>支持多种协议</li><li>并行快速扫描</li><li>与其他工具集成</li></ul><h2 id="如何安装nuclei" tabindex="-1">如何安装Nuclei <a class="header-anchor" href="#如何安装nuclei" aria-label="Permalink to &quot;如何安装Nuclei&quot;">​</a></h2><p>在安装Nuclei之前，请确保你已经安装了Go语言环境以及相关的依赖。以下命令用于安装Nuclei：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Linux:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt-get</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nuclei</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> </span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Win:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> go</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -u</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> github.com/projectdiscovery/nuclei/v2/cmd/nuclei</span></span></code></pre></div><h2 id="如何使用nuclei" tabindex="-1">如何使用Nuclei <a class="header-anchor" href="#如何使用nuclei" aria-label="Permalink to &quot;如何使用Nuclei&quot;">​</a></h2><p>仔细按照以下示例操作，到文章末尾，你将对这个工具非常熟悉。如果你能持续练习2-4小时，你将成为一个专业用户。</p><p>努力工作，直到你达到目标，让我们开始吧！</p><h3 id="默认模式" tabindex="-1">默认模式 <a class="header-anchor" href="#默认模式" aria-label="Permalink to &quot;默认模式&quot;">​</a></h3><p>在默认模式下，我们只需要提供一个域名作为扫描目标，无需添加其他命令。此外，如果存在开放端口，我们可以将其添加到命令中，以获得更具体的结果。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">nuclei</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -u</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://techyrick.com</span></span></code></pre></div><p><img src="`+l+'" alt=""></p><p>我发现我的站点存在开放端口，并且我想扫描其中的22号端口（SSH）。</p><p><img src="'+p+'" alt=""></p><p>这些命令将使用Nuclei扫描数千种已知的漏洞，并枚举目标的相关信息。扫描结果非常出色，你可以尝试在我的站点上进行扫描，查看详细的DNS记录结果。我对此感到非常惊讶。</p><h3 id="扫描多个站点" tabindex="-1">扫描多个站点 <a class="header-anchor" href="#扫描多个站点" aria-label="Permalink to &quot;扫描多个站点&quot;">​</a></h3><p>为了扫描多个站点，我们可以添加<code>-l</code>命令。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">nuclei</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -l</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> domains.txt</span></span></code></pre></div><p><img src="'+h+'" alt=""></p><h3 id="工具集成" tabindex="-1">工具集成 <a class="header-anchor" href="#工具集成" aria-label="Permalink to &quot;工具集成&quot;">​</a></h3><p>我们可以集成多个工具来减少工作量并获得更出色的结果。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">subfinder</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> domains.txt</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> httpx</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> nuclei</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -t</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;http/technologies/prestashop-detect.yaml&quot;</span></span></code></pre></div><p><img src="'+n+'" alt=""></p><h3 id="过滤" tabindex="-1">过滤 <a class="header-anchor" href="#过滤" aria-label="Permalink to &quot;过滤&quot;">​</a></h3><p>如果你不知道针对目标应该使用哪个模板，那么直接使用自动选择功能即可。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">nuclei</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -u</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://techyrick.com</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -as</span></span></code></pre></div><p><img src="'+c+'" alt=""></p><p>如果你想使用最新的模板，可以尝试以下命令。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">nuclei</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -u</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://techyrick.com</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -nt</span></span></code></pre></div><p><img src="'+r+'" alt=""></p><p>我们还可以添加特定的模板来扫描目标。</p><p><img src="'+o+'" alt=""></p><p>你知道的，我们可以通过标签进行过滤，请查看下面的命令。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">nuclei</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -u</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://jira.techyrick.com</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -tags</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> jira,generic</span></span></code></pre></div><p>按严重性选择模板。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">nuclei</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -u</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://techyrick.com</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> critical,high,medium,low,info</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -as</span></span></code></pre></div><p><img src="'+k+'" alt=""></p><h3 id="模板" tabindex="-1">模板 <a class="header-anchor" href="#模板" aria-label="Permalink to &quot;模板&quot;">​</a></h3><p>想知道我从哪里获取的模板吗？请查看以下链接：</p><p><a href="https://nuclei-templates.netlify.app/" target="_blank" rel="noreferrer">https://nuclei-templates.netlify.app/</a></p><p>在搜索选项中，你可以输入任何你需要的内容。例如，如果你需要DNS结果，只需输入DNS并复制yaml脚本并针对目标运行即可。</p><p>你还可以找到许多有关OSINT、PD Teams、CVE-2023、RCE和接管的模板。</p><p><img src="'+d+'" alt=""></p><p><img src="'+g+'" alt=""></p><h3 id="速率限制" tabindex="-1">速率限制 <a class="header-anchor" href="#速率限制" aria-label="Permalink to &quot;速率限制&quot;">​</a></h3><p>可以使用<code>-rlm &amp;lt;int&amp;gt;</code> 选项以每分钟请求数的形式指定速率限制。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">nuclei</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -u</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://techyrick.com/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -rl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 3</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 2</span></span></code></pre></div><p><img src="'+u+'" alt=""></p><p>我们还可以设置超时、重试和错误次数。</p><ul><li>超时时长(-timeout)（默认值是5）</li><li>重试次数(-retries)</li><li>错误次数(-mhe)</li></ul><h3 id="恢复扫描" tabindex="-1">恢复扫描 <a class="header-anchor" href="#恢复扫描" aria-label="Permalink to &quot;恢复扫描&quot;">​</a></h3><p>我们还可以恢复扫描，所有的扫描结果将保存在<code>/home/user/.config</code> 目录下。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">nuclei</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -l</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> domains.txt</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -resume</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /home/rick/.config/nuclei/resume-ci5g1996u63ag4n7897g.cfg</span></span></code></pre></div><p><img src="'+F+'" alt=""></p><h2 id="结论" tabindex="-1">结论 <a class="header-anchor" href="#结论" aria-label="Permalink to &quot;结论&quot;">​</a></h2><p>在我个人看来，这是最好的漏洞分析下工具之一。使用它非常有趣，而且比Nikto更好。</p><p>我们下篇文章再见。</p>',66)])])}const N=s(m,[["render",b]]);export{S as __pageData,N as default};
